const { exec, spawn } = require('child_process');
const { promisify } = require('util');
const os = require('os');
const fs = require('fs').promises;
const path = require('path');

const execAsync = promisify(exec);
const CORES = os.cpus().length;

const config = {
    nodeEnv: process.env.NODE_ENV || 'production',
    deployTarget: process.env.DEPLOY_TARGET || 'production',
    pm2AppName: process.env.PM2_APP_NAME,
    deployScript: process.env.DEPLOY_SCRIPT,
    dockerImage: process.env.DOCKER_IMAGE,
    remoteServer: process.env.REMOTE_SERVER,
    remotePath: process.env.REMOTE_PATH,
    healthCheckUrl: process.env.HEALTH_CHECK_URL,
    skipTests: process.env.SKIP_TESTS === 'true',
    skipBuild: process.env.SKIP_BUILD === 'true'
};

const log = (message) => {
    console.log(`[${new Date().toISOString()}] ${message}`);
};

const error = (message) => {
    console.error(`[ERROR] ${message}`);
    process.exit(1);
};

const execWithOutput = (command, options = {}) => {
    return new Promise((resolve, reject) => {
        const child = spawn(command, {
            shell: true,
            stdio: 'inherit',
            ...options
        });

        child.on('close', (code) => {
            if (code !== 0) {
                reject(new Error(`Command failed: ${command}`));
            } else {
                resolve();
            }
        });
    });
};

const checkPackageManager = async () => {
    try {
        await execAsync('pnpm --version');
        return 'pnpm';
    } catch {
        try {
            await execAsync('yarn --version');
            return 'yarn';
        } catch {
            return 'npm';
        }
    }
};

const installDependencies = async () => {
    log('Installing dependencies with parallel optimization...');
    const pm = await checkPackageManager();

    const commands = {
        pnpm: 'pnpm install --frozen-lockfile --prefer-offline --reporter=silent',
        yarn: `yarn install --frozen-lockfile --prefer-offline --silent --network-concurrency ${CORES * 2}`,
        npm: `npm ci --prefer-offline --no-audit --no-fund --maxsockets=${CORES * 2}`
    };

    await execWithOutput(commands[pm]);
};

const runTests = async () => {
    if (config.skipTests) {
        log('Skipping tests (SKIP_TESTS=true)');
        return;
    }

    log('Running tests in parallel...');

    try {
        const hasJest = await fs.access('jest.config.js').then(() => true).catch(() => false) ||
                       await fs.access('jest.config.json').then(() => true).catch(() => false);
        
        const hasVitest = await fs.access('vitest.config.js').then(() => true).catch(() => false) ||
                         await fs.access('vitest.config.ts').then(() => true).catch(() => false);

        if (hasJest) {
            await execWithOutput(`npm test -- --maxWorkers=${CORES} --bail --silent --coverage=false`);
        } else if (hasVitest) {
            await execWithOutput(`npm test -- --threads --maxThreads=${CORES} --bail`);
        } else {
            await execWithOutput('npm test');
        }
    } catch (err) {
        error(`Tests failed: ${err.message}`);
    }
};

const buildApplication = async () => {
    if (config.skipBuild) {
        log('Skipping build (SKIP_BUILD=true)');
        return;
    }

    log('Building application...');

    process.env.NODE_OPTIONS = '--max-old-space-size=4096';

    try {
        const hasNext = await fs.access('next.config.js').then(() => true).catch(() => false);
        const hasVite = await fs.access('vite.config.js').then(() => true).catch(() => 
                       fs.access('vite.config.ts').then(() => true).catch(() => false));
        const hasWebpack = await fs.access('webpack.config.js').then(() => true).catch(() => false);

        if (hasNext) {
            await execWithOutput('npm run build -- --parallel');
        } else if (hasVite) {
            await execWithOutput('npm run build');
        } else if (hasWebpack) {
            await execWithOutput('npm run build -- --mode production');
        } else {
            await execWithOutput('npm run build');
        }
    } catch (err) {
        error(`Build failed: ${err.message}`);
    }
};

const deployToProduction = async () => {
    log(`Deploying to ${config.deployTarget}...`);

    if (config.pm2AppName) {
        try {
            await execAsync('pm2 --version');
            await execWithOutput(`pm2 reload ${config.pm2AppName} --update-env`);
        } catch {
            await execWithOutput('pm2 start ecosystem.config.js');
        }
    }

    if (config.deployScript) {
        await execWithOutput(`bash ${config.deployScript}`);
    }

    if (config.dockerImage) {
        await execWithOutput(`docker build -t ${config.dockerImage} --build-arg NODE_ENV=production .`);
        await execWithOutput(`docker push ${config.dockerImage}`);
    }

    if (config.remoteServer && config.remotePath) {
        await execWithOutput(
            `rsync -avz --delete --exclude='node_modules' --exclude='.git' ` +
            `-e "ssh -o StrictHostKeyChecking=no" ./ ${config.remoteServer}:${config.remotePath}/`
        );
        
        await execWithOutput(
            `ssh ${config.remoteServer} "cd ${config.remotePath} && npm ci --production && pm2 reload all"`
        );
    }
};

const healthCheck = async () => {
    if (!config.healthCheckUrl) {
        return;
    }

    log('Running health check...');
    
    for (let i = 0; i < 10; i++) {
        try {
            const response = await fetch(config.healthCheckUrl);
            if (response.ok) {
                log('Health check passed');
                return;
            }
        } catch (err) {
            await new Promise(resolve => setTimeout(resolve, 2000));
        }
    }
    
    error('Health check failed');
};

const main = async () => {
    const startTime = Date.now();
    
    log(`Starting CI/CD pipeline for ${config.deployTarget}`);
    log(`Using ${CORES} CPU cores`);

    try {
        log('Step 1/5: Installing dependencies');
        await installDependencies();

        log('Step 2/5: Running tests');
        await runTests();

        log('Step 3/5: Building application');
        await buildApplication();

        log('Step 4/5: Deploying to production');
        await deployToProduction();

        log('Step 5/5: Health check');
        await healthCheck();

        const duration = ((Date.now() - startTime) / 1000).toFixed(2);
        log(`Pipeline completed successfully in ${duration}s`);
    } catch (err) {
        error(`Pipeline failed: ${err.message}`);
    }
};

main();